import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.HashSet;
import java.util.Set;

/**
 * An inventory consumer that consumes messages from the "inventory-updates" topic
 * and processes them idempotently.
 */
public class InventoryConsumer {
    private final KafkaConsumer<String, String> consumer;
    private final Set<String> processedMessages;
    private volatile boolean running = true;

    /**
     * Constructs an InventoryConsumer with the given bootstrap servers.
     *
     * @param bootstrapServers The Kafka broker addresses
     */
    public InventoryConsumer(String bootstrapServers) {
        Properties props = new Properties();

        // Use ConsumerConfig constants for all configuration keys
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "inventory-consumer-group");
        props.put(ConsumerConfig.CLIENT_ID_CONFIG, "inventory-consumer-client");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        this.consumer = new KafkaConsumer<>(props);
        this.processedMessages = new HashSet<>();
    }

    /**
     * Starts consuming messages from the inventory-updates topic.
     * Processes messages idempotently and commits offsets after each batch.
     */
    public void start() {
        try {
            consumer.subscribe(Collections.singletonList("inventory-updates"));

            while (running) {
                // Use poll(Duration) API - not the deprecated poll(long)
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                if (!records.isEmpty()) {
                    // Process batch of records
                    for (ConsumerRecord<String, String> record : records) {
                        processRecord(record);
                    }

                    // Commit offsets synchronously after processing each batch
                    consumer.commitSync();
                }
            }
        } catch (WakeupException e) {
            // Handle WakeupException for clean shutdown
            System.err.println("Consumer was woken up for shutdown");
        } catch (Exception e) {
            System.err.println("Error in consumer: " + e.getMessage());
            e.printStackTrace();
        } finally {
            consumer.close();
            System.out.println("Consumer closed");
        }
    }

    /**
     * Processes a single consumer record idempotently.
     * Tracks processed messages to ensure exactly-once semantics.
     *
     * @param record The consumer record to process
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        String messageKey = record.key() + "-" + record.partition() + "-" + record.offset();

        // Idempotent processing: skip if we've already processed this exact message
        if (processedMessages.contains(messageKey)) {
            System.out.println("Skipping duplicate message: " + messageKey);
            return;
        }

        // Process the inventory update
        System.out.println("Processing inventory update - Key: " + record.key() +
                         ", Value: " + record.value() +
                         ", Partition: " + record.partition() +
                         ", Offset: " + record.offset());

        // Mark message as processed for idempotency
        processedMessages.add(messageKey);
    }

    /**
     * Stops the consumer gracefully.
     */
    public void stop() {
        running = false;
        consumer.wakeup();
    }

    /**
     * Main method to demonstrate usage
     */
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java InventoryConsumer <bootstrap-servers>");
            System.exit(1);
        }

        String bootstrapServers = args[0];
        InventoryConsumer consumer = new InventoryConsumer(bootstrapServers);

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down consumer...");
            consumer.stop();
        }));

        consumer.start();
    }
}

